const shapeSortConfig = {
  tileSizePx: 96,        // was 72 — larger touch target on mobile
  dragPaddingPx: 16,     // was 6  — easier to grab tiles with a finger
  snapTolerancePx: 32,   // was 16 — more forgiving drop zone on mobile
};

.shape-sort-board {
  min-height: 360px;
  padding: 16px;
}

.shape-tile {
  width: 72px;
  height: 72px;
  border-radius: 18px;
}

/* Mobile: larger tiles for easier touch interaction */
@media (max-width: 600px), (pointer: coarse) {
  .shape-tile {
    width: 96px;
    height: 96px;
    border-radius: 24px;
  }
}

